window.EVENTS_DETAILS = [{"event": "The Abstract Earth", "place": "Main Entrance", "date": "2026-05-07", "time": "2026-05-07, 10:00 am–11:00 am", "category": "concert", "url": "https://www.superbooth.com/en/events/details/the-abstract-earth.html", "details": "For decades, Charles Matuschewski has been shaping the Berlin music scene as a pianist, keyboardist, trumpeter, and producer. His current project, “The Abstract Earth Solo works,” uniquely combines analog live acoustic improvisation with electronic soundscapes. The result is a fascinating sound laboratory that draws the listener into a flowing dialogue between jazz, electronic, soul, and neo-classical music.\n\nWebsite:\n\nwww.theabstractearth.com"}, {"event": "SooperRadio: Radio Woltersdorf & PiRadio", "place": "SooperRADIO", "date": "2026-05-07", "time": "2026-05-07, 10:00 am", "category": "radio", "url": "https://www.superbooth.com/en/events/details/sooperradio-radio-woltersdorf-piradio-2.html", "details": "is our live radio format from the Superbooth team. We´ve now been broadcasting for over 4 years as part of the Radio Woltersdorf program in Berlin and Potsdam on the frequency of the independent station Piradio.\n\nStarting on Thursday, May 7th, 2026 we will broadcast LIVE from the Superbooth!\n\n24 hours of nerdtalk, gossip, education, madness - directly from the Pionierpalast to your radio.\n\nWe appreciate the participatory approach of everyone involved in the event and are looking forward to the musically rich program (check the line-up!!!).\n\nSo tune in your radios and remember: \"Every ten minutes a person falls in love with a modular system\" (A. Schneider)..\n\nRadio frequency 88.4 MHz in Berlin or in Potsdam on 90.7 MHz or via live-stream on piradio.de"}, {"event": "Ambient Dub Café till noon", "place": "Sooper Corner", "date": "2026-05-07", "time": "2026-05-07, 10:00 am–12:00 pm", "category": "ambient", "url": "https://www.superbooth.com/en/events/details/ambient-dub-cafe-till-noon-2.html", "details": "The mono-chill ambient sounds are back for SB26 – on the Super-Power Sound System every morning until noon. Grab a coffee and relax with the Berlin Dubcafé crew."}, {"event": "DIY Workshop - Zlob Modular", "place": "DIY-Area", "date": "2026-05-07", "time": "2026-05-07, 11:00 am–2:00 pm", "category": "diy", "url": "https://www.superbooth.com/en/events/details/diy-workshop-zlob-modular.html", "details": "Attenumixer /// DIY Level: Easy /// Price: 45€ or Miniatt /// DIY Level: Easy /// Price: 50€\n\nIn this DIY workshop, participants will build either the Zlob Attenumixer or the MiniAtt, two compact and highly useful Eurorack utility modules.\n\nThe Zlob Attenumixer is a 4HP passive three-channel attenuator and mixer, ideal for shaping and combining control voltages and audio signals in your modular system.\n\nThe MiniAtt is an ultra-compact 2HP two-channel switched attenuator, mixer, and offset generator that can operate in either active or passive mode.\n\nBoth modules feature reversible front panels, allowing you to choose between a clean minimal look or a graphic design. During the workshop you will solder and assemble the module yourself and learn about its functions and applications in modular synthesis."}, {"event": "DIY Workshop - Tubbutec", "place": "DIY-Area", "date": "2026-05-07", "time": "2026-05-07, 11:00 am–2:00 pm", "category": "diy", "url": "https://www.superbooth.com/en/events/details/diy-workshop-tubbutec.html", "details": "Drummertime /// DIY Level: Medium /// Price: 185€\n\nBuild your own Tubbutec Drummertime Step Sequencer!\n\nWe offer all four versions:\n\nMore information about the module can be found on our website: www.tubbutec.de/drummertime\n\nWe kindly ask all participants of this workshop to arrive sober."}, {"event": "FLINTA* Workshop for Modular Beginners (auf Deutsch)", "place": "Flinta*Area", "date": "2026-05-07", "time": "2026-05-07, 11:00 am–12:00 pm", "category": "flinta", "url": "https://www.superbooth.com/en/events/details/flinta-workshop-for-modular-beginners-auf-deutsch.html", "details": "FLINTA* workshops are exclusively for women, trans, non-binary, and gender-expansive people.\n\nDue to high demand, we will be offering a Modular Beginner Workshop in German this year again.\n\nOur yearly introductory workshop for FLINTA* (women, trans, non-binary, and gender-expansive people) is intended as an opportunity to learn more about the world of modular synthesis in a relaxed and inclusive atmosphere.\n\nThe workshop on Thursday will be hosted by lil.lili. Lil.lili is currently making waves in the music scene with her unique blend of electronic beats and catchy melodies. Her high-energy live performances and creative sound have earned her a growing fanbase. In addition to her music, she is dedicated to introducing other FLINTA individuals to the world of synthesizers and helping them overcome the fear of the so-called \"intimidating\" technology.\n\nPlease note: To enter the workshop you need a Superbooth ticket for the the day (or a 3-day ticket) + the free of charge workshop ticket itself. Both Tickets are vailable HERE in our ticket shop.\n\n*** This workshop will be held in German.***"}, {"event": "Modular Beginner Workshop", "place": "Kino", "date": "2026-05-07", "time": "2026-05-07, 11:00 am–12:00 pm", "category": "workshop", "url": "https://www.superbooth.com/en/events/details/modular-beginner-workshop-6.html", "details": "Modular Beginner Workshop for all\n\nWe will cover the essential topics and basic vocabulary necessary to understand the principles of synthesis and patching. Join us and and we’ll help you be on your way to navigating the world of modular synthesis.\n\nAll are welcome and there is no booking required for this workshop .\n\nThis workshop will be held in English."}, {"event": "Sacha Ketterlin", "place": "Seebühne", "date": "2026-05-07", "time": "2026-05-07, 11:00 am–11:40 am", "category": "concert", "url": "https://www.superbooth.com/en/events/details/sacha-ketterlin-3.html", "details": "Sacha Ketterlin is a Berlin-based producer and live performer working across techno and ambient music.\n\nWith a background in classical piano, his sets focus on atmosphere, depth and subtle tension rather than obvious peaks. His sound moves between immersive textures and low-end driven structures, shaped for listening as much as for physical impact.\n\nHe is the founder of Intumi Records, an independent platform for electronic music centered on depth, mood and carefully crafted sound design\n\nInstagram | Soundcloud"}, {"event": "Workshop - DSP-Dealer", "place": "Workshop Room", "date": "2026-05-07", "time": "2026-05-07, 12:30 pm–2:00 pm", "category": "workshop", "url": "https://www.superbooth.com/en/events/details/workshop-dsp-dealer.html", "details": "In this workshop, David Nowotny (Dycide), developer of *Inspect* at DSP Dealer, offers insights into the development of real-time audio and visual software in C++. Using *Inspect* as a practical example, he shows how audiovisual tools can be built to meet the specific demands of real-time systems.\n\nThe workshop focuses on core topics such as real-time safety, working with multiple real-time threads, and safe as well as efficient data sharing between audio processing, analysis, and rendering. Drawing on practical examples from the development of *Inspect*, David explores how technical precision and creative application can come together in audiovisual software."}, {"event": "LXC + Toni Wobble", "place": "Sooper Corner", "date": "2026-05-07", "time": "2026-05-07, 12:40 pm–2:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/lxc-b2b-toni-wobble.html", "details": "LXC from Leipzig works sonically between Ambient and Hardcore, focusing on broken beats, dubwise soundscapes, and heavy subbass. Active since the early 1990s—from experimental 8-bit studies to noisy Drum & Bass live acts—he has released numerous records on international labels, developing a distinctive style between Jungle, Dub, and extreme bass music.\n\nBeyond his own music, LXC runs the Leipzig-based Drum & Bass/Jungle label Alphacut Records with several sublabels. He also works as a promoter, mastering engineer, and vinyl cutter, including at RAND Muzik. International performances across Europe have cemented his place in the experimental bass underground.\n\nLXC | Alphacut Records"}, {"event": "VMO - Volca Massaker Orchester", "place": "Seebühne", "date": "2026-05-07", "time": "2026-05-07, 1:00 pm–1:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/volca-massaker-orcherster.html", "details": "Since 2014 the orchestra has used only the Volca electronic device, made by musical instrument maker KORG, to play improvised electronic music. The little devices can be linked and so keep the same beat as they are connected by a cable. There is no repertoire – the pieces are reinvented every time, nothing is prefabricated.\n\nThe orchestra currently consists of Daniel Wihler, Nicolas Kellner, Maru Rieben, Annie Rüfenacht and Pete Leuenberger.\n\nVolca Massaker Orchester | Instagram"}, {"event": "Modular Synthesizer Ensemble", "place": "Auditorium", "date": "2026-05-07", "time": "2026-05-07, 1:30 pm–1:50 pm", "category": "workshop", "url": "https://www.superbooth.com/en/events/details/modular-synthesizer-ensemble-13.html", "details": "The result of a 4-hour workshop with school students will be presented. From 9 a.m. to 1 p.m. they will patch, experiment, improvise and work on a composition together.\n\nThe MODULAR SYNTHESIZER ENSEMBLE shows impressively that it is also possible to make music together with 12 modular synthesizers. The project enables immediate and intuitive access to electronic music even without any previous knowledge and is therefore open to everyone.\n\nThe project format was developed by Gammon, in cooperation with two Viennese schools, before it was presented for the first time during Superbooth 2017. \"The essential thing for me is the shared musical process and the sensual experience in the group. From the first cable connection to the live performance without any previous knowledge. But even for the experienced, it is an exciting challenge to play together in a larger group.\" says Gammon."}, {"event": "Korg Berlin - Live Presentation", "place": "Strandbühne", "date": "2026-05-07", "time": "2026-05-07, 2:00 pm–2:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/korg-berlin-live-presentation.html", "details": "Introducing a new format of product presentations on our festival stage the 'Strandbühne' with Korg Berlin . More details coming soon."}, {"event": "Gesprächskonzert - u-he", "place": "Kino", "date": "2026-05-07", "time": "2026-05-07, 2:30 pm–2:50 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/gespraechskonzert-u-he-7.html", "details": "More Information coming soon...."}, {"event": "DjBadshape", "place": "Sooper Corner", "date": "2026-05-07", "time": "2026-05-07, 2:40 pm–4:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/djbadshape.html", "details": "Come join and get in shape!\n\nWith more than 10 years of experience captivating audiences, this Leipzig-based dynamo has become synonymous with the city's club scene. Whether it's jungle, techno, or experimental electronica - when DjBadshape is behind the decks, her main focus is on having fun and making sure you do too by crossing genres and tempos to keep the energy high.\n\nCheck out her releases on Defrostatica and Sozialistischer Plattenbau on Bandcamp, as well as the VA releases and monthly uploads of her Temper mixes on SoundCloud ."}, {"event": "FLINTA* Workshop - Sequencing Techniques in Modular Synthesizers", "place": "Flinta*Area", "date": "2026-05-07", "time": "2026-05-07, 3:00 pm–4:00 pm", "category": "flinta", "url": "https://www.superbooth.com/en/events/details/flinta-workshop-sequencing-techniques-in-modular-synthesizers.html", "details": "FLINTA* workshops are exclusively for women, trans, non-binary, and gender-expansive people.\n\nSequencing Techniques in Modular Synthesizers:\n\nThis workshop is designed for those who have some experience and are ready to dive deeper. We’ll be exploring sequencing techniques in modular synthesizers. This means focusing on how to create dynamic movement within patches— not just using sequencers, but leveraging core elements of modular systems, such as switches, clock dividers, LFOs, and more.\n\nTogether, we’ll experiment with various patches and embrace the concept of “modular thinking.”\n\nPlease note: To enter the workshop you need a Superbooth ticket for the the day (or a 3-day ticket) + the workshop ticket itself. Both Tickets are vailable HERE in our ticket shop."}, {"event": "DIY Workshop - LeafAudio", "place": "DIY-Area", "date": "2026-05-07", "time": "2026-05-07, 3:00 pm–6:00 pm", "category": "diy", "url": "https://www.superbooth.com/en/events/details/diy-workshop-leafaudio-3.html", "details": "VCF-X /// DIY Level: Medium /// Price: 139€\n\nExclusively available in this workshop before its official release! The LeafAudio VCF-X carries forward a unique analog filter design originally developed by TubeOhm - now officially continued and supported by LeafAudio.\n\nAt its core, the circuit combines two well-established concepts: the SMR4, known for its warm, smooth and musical character, and the 4PM (4-Pole Mission), which introduced a wide range of selectable filter responses. This fusion results in a rich-sounding 4-pole filter that feels organic and full, offering far more flexibility than classic single-mode designs.\n\nThe Mode control lets you move through 15 different filter types and slopes – from lowpass, highpass and bandpass to notch and phaser-style responses. The current setting is shown on the built-in LED matrix what makes it intuitive to explore and perform with. And it includes a VCA!"}, {"event": "DIY Workshop - Thonk Synth", "place": "DIY-Area", "date": "2026-05-07", "time": "2026-05-07, 3:00 pm–6:00 pm", "category": "diy", "url": "https://www.superbooth.com/en/events/details/diy-workshop-thonk-synth.html", "details": "T01 VCO /// DIY Level: Easy /// Price: 90€\n\nT07 Triple Mod/// DIY Level: Medium /// Price: 170€\n\nT08 Double Bubble /// DIY Level: Medium /// Price: 215€\n\nThonk Synth are the leading synth DIY store in the UK and we're excited to bring our in-house Eurorack range to Superbooth. Come and build one of our greatest hits! Beginners are very welcome."}, {"event": "Stromkult - In Conversation with Anna Z", "place": "Stromkult Stage", "date": "2026-05-07", "time": "2026-05-07, 3:00 pm–3:30 pm", "category": "talk", "url": "https://www.superbooth.com/en/events/details/stromkult-in-conversation-with-anna-z.html", "details": "For the first time this year, Stromkult , in collaboration with the SuperBooth and SchneidersLaden, is hosting a stage for conversations about electronic music and making electronic music in the cozy Bungalowdorf area of the SuperBooth. Rather than focusing on direct product demos, the idea behind this stage is to provide insight into the philosophies and working processes of the people behind the instruments – as well as the artists using them – through casual live conversation panels."}, {"event": "Nika Son", "place": "Seebühne", "date": "2026-05-07", "time": "2026-05-07, 3:00 pm–3:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/nika-son.html", "details": "Nika Son works as a musician, artist, film composer, DJ and curator in Hamburg. In her compositions, video- and soundworks she examines multi-sensory perception, its bounderies and interaction, but also forms of manipulation and illusion.\n\nWeaving oneiric musique concrète with analog and digital synthesis, broken rhythms, voices and modulated tape, her work captures the fluid, ever-shifting nature of the night, making the familiar strange and the surreal strangely familiar. Sounds of various origin are translated into a very unusual musical language, as if one watches the audible.\n\nHer debut album was released on the label Entr'acte/Stellage in 2020. Her new album Aslope came out 2024 on V I S, as well as the soundtrack DRIFT on Futura Resistenza.\n\nFurthermore she hosts regular art and music events at various venues, mainly at Golden Pudel Club in Hamburg. Since 2019 she is co-curator of the festival Papiripar.\n\nNika Son | Instagram | Soundcloud\n\nPhoto credit: Ralf Köster"}, {"event": "Workshop - Bitwig", "place": "Workshop Room", "date": "2026-05-07", "time": "2026-05-07, 3:30 pm–4:30 pm", "category": "workshop", "url": "https://www.superbooth.com/en/events/details/workshop-bitwig-4.html", "details": "In this session, we will explore the overhauled automation editing, the powerful new automation clips, clip aliases, and key signature support. Find out how Bitwig Studio 6 can take your music-making to another level."}, {"event": "Gesprächskonzert - DSP Dealer", "place": "Kino", "date": "2026-05-07", "time": "2026-05-07, 3:30 pm–3:50 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/gespraechskonzert-dsp-dealer.html", "details": "In this talk concert, artist and producer Polygonia offers insights into her work with visual sound analysis. The starting point is the goniometer module of the audio analysis software Inspect, developed by her company DSP Dealer, which is also exhibiting at Superbooth. A goniometer visualizes spatial properties of audio signals and provides an additional perspective on sonic processes. Through visual representations, Polygonia presents some of her observations related to harmony as well as other interesting phenomena that emerge in the context of sound synthesis and signal design."}, {"event": "Tymek Papior", "place": "Tonarium/Studiobühne", "date": "2026-05-07", "time": "2026-05-07, 4:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/tymek-papior.html", "details": "Tymek Papior – multi-instrumentalist, composer, and producer. Using an arsenal of prepared instruments, such as a modified drum kit, his younger sister's harp, a broken accordion, and lo-fi field recordings, Tymek Papior augments his unique acoustic soundscapes and juxtaposes them with heavily distorted, raw digital sounds and synthesizers, combining electroacoustic sound design and improvisation into compositions full of different textures and spaces. His approach is best heard on his solo albums „Rugs/Carpets” released in August 2024 and „WSPÓLNA SPRAWA LP” released in January 2026.\n\nHis performance take place as part of the Tonarium exhibition.\n\nRA | Instagram | Bandcamp"}, {"event": "TBA", "place": "Strandbühne", "date": "2026-05-07", "time": "2026-05-07, 4:00 pm–4:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/tba-2.html", "details": "To be announced soon."}, {"event": "Gesprächskonzert - Erica Synths", "place": "Kino", "date": "2026-05-07", "time": "2026-05-07, 4:30 pm–4:50 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/gespraechskonzert-erica-synths-4.html", "details": "More Information coming soon...."}, {"event": "Banu", "place": "Sooper Corner", "date": "2026-05-07", "time": "2026-05-07, 4:40 pm–6:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/banu.html", "details": "As a DJ and electronic music producer, Banu finds herself between music, sound art installations and research, using music as an artistic tool for activism. Growing up in South Eastern Turkey in the underground rave scene and currently based in Berlin, she specializes in composing with analog synthesizers  that are versatile with a groovy bounce. Banu creates uncanny experiences in her live sets by using sound design as unique transitions that blur the lines between music and sound art. She believes in the political possibility of sound and music, which she utilizes as an empowerment tool for minority groups with an emphasis on BIPOC and LGBTQI+ communities.\n\nBanu has played renowned Berlin clubs such as Berghain along with touring major European and African venues like Bassiani Tbilisi and Modular Cape Town. Banu’s work has been awarded one of the Top Albums of 2022 by DJ Mag and received critical acclaim from other publications such as Clot Magazine. She has won numerous fellowships for her work, including a residency for young music producers in Namibia called Electric Desert. She is also a resident at Refuge Worldwide Radio in Berlin.\n\nInstagram | BCT\n\nPhoto credit: Jörg Dedering"}, {"event": "Stromkult - In Conversation with SchneidersLaden Berlin", "place": "Stromkult Stage", "date": "2026-05-07", "time": "2026-05-07, 5:00 pm–5:30 pm", "category": "talk", "url": "https://www.superbooth.com/en/events/details/stromkult-in-conversation-with-schneidersladen-berlin.html", "details": "For the first time this year, Stromkult , in collaboration with the SuperBooth and SchneidersLaden, is hosting a stage for conversations about electronic music and making electronic music in the cozy Bungalowdorf area of the SuperBooth. Rather than focusing on direct product demos, the idea behind this stage is to provide insight into the philosophies and working processes of the people behind the instruments – as well as the artists using them – through casual live conversation panels."}, {"event": "Electric Indigo", "place": "Seebühne", "date": "2026-05-07", "time": "2026-05-07, 5:00 pm–5:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/electric-indigo.html", "details": "Susanne Kirchmayr aka Electric Indigo, DJ, composer, musician has performed in 45 countries across Europe, Asia, and the Americas. She represents an intelligent and distinguished interpretation of techno and electronic music. In 1998 she founded the transnational female:pressure network for which she received an Honorary Mention at Prix Ars Electronic in 2009. The Republic of Austria awarded her with the Kunstpreis Musik in 2020. Electric Indigo premiered her compositions at festivals like Wien Modern, Musikprotokoll, CTM or Heroines of Sound and composed for Klangforum Wien. Her debut album “5 1 1 5 9 3” came out on Imbalance Computer Music, followed by \"Ferrum\" on Editions Mego in 2020. “Brittle” was released on Ventil Records in 2022.\n\nElectric Indigo\n\nPhoto credit: Elsa Okazaki"}, {"event": "Gesprächskonzert - Ploytec", "place": "Kino", "date": "2026-05-07", "time": "2026-05-07, 5:30 pm–5:50 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/gespraechskonzert-ploytec-7.html", "details": "Catch Ploytec presenting the latest on USB Audio and Revival, featuring a live demonstration of the BoomKick V2 by Dobbroman."}, {"event": "Surgeons Girl", "place": "Strandbühne", "date": "2026-05-07", "time": "2026-05-07, 6:00 pm–6:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/surgeons-girl.html", "details": "Bristol-based artist Surgeons Girl emerged with the immersive, otherworldly synth explorations of A Violet Sleep , a dream-like debut released on Livity Sound. She followed this with The Empress Moss on Inside Out Records and Sever on Lapsus Records, carving out a distinctive sound rooted in exploratory, synth-rich techno. In 2026, Surgeons Girl returns to Livity Sound with A Moment To Machine , an EP that deepens and sharpens this vision.\n\nAlongside a carefully curated discography, she has built a strong reputation for hardware-led live performance, appearing at venues including Berghain, Akademie der Künste, ICA, Southbank Centre (QEH), La Trabendo Paris, Doka Amsterdam, and Machina Bristronica. Her work also spans audiovisual commissions, including Into the Universe / IKLECTIK alongside Rrose, and an ongoing collaboration with filmmaker Daisy Dickinson.\n\nAs a DJ, she has shared line-ups with Upsammy, Konduku, Luke Slater, and Pariah. Surgeons Girl hosts a monthly residency on Rinse FM / SWU, spotlighting ambient through techno with a strong emphasis on live performance. She is also a member of the newly formed Death in Vegas live trio, touring throughout the year.\n\nInstagram | Bandcamp | Youtube"}, {"event": "Alex Solman + Resom", "place": "Sooper Corner", "date": "2026-05-07", "time": "2026-05-07, 6:40 pm–8:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/alex-solman-resom.html", "details": "Alex Solman is well known as the in-house illustrator of Hamburg’s Golden Pudel Club. What many don’t know is that he’s also a passionate flea market hunter—one who returns home in a foul mood if he comes back empty-handed. The top selector for all occasions, uncompromising, and Resom, the former globe-trotting DJ of electronic realms, met in the Pudel universe over ten years ago. Since then, they’ve been connected not only by their love for each other but, above all, by their shared passion for music. Sounds good, hits the heart, and lifts the soul.\n\nResom | Alex Solman"}, {"event": "WSNWG [LIVE] - Rødhåd + Lady Starlight", "place": "Seebühne", "date": "2026-05-07", "time": "2026-05-07, 7:00 pm–7:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/wsnwg-live-rodhad-lady-starlight.html", "details": "When Lady Starlight and Rødhåd come togther live on the Seebühne, expectations shift. Known respectively for raw hardware performances and deep, driving Berlin techno, this collaboration moves beyond their usual dancefloor trajectories unexpected directions."}, {"event": "Anna Z + J. Manuel", "place": "Strandbühne", "date": "2026-05-07", "time": "2026-05-07, 8:00 pm–8:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/anna-z-j-manuel.html", "details": "ANNA Z is an interdisciplinary artist with roots in architecture and coding-based visual art. Driven by a deep love for hardware, especially modular synthesizers, she has woven her presence as Live-Performer and DJ into renowned clubs and events, including Tresor, Blitz, Berghain, Bassiani, Fuse, La Gaîté Lyrique and others. Her bold and distinctive performances, bursting with imaginative sound design experiments, have become a defining feature of her influence within the dynamic musical landscape.\n\nSince 2021 ANNA Z has hosted her own radio show KOMI on Radio80k, a noncommercial community radio in Germany. KOMI believes in the spirit of the forest and nature, free and independent like a Nordic wind, and is open to all kinds of electronic and contemporary music.\n\nAnna’s artistic practice emerges from a wide range of experiments, including programming, hardware, including drawing and mixed media art — always with music at the center.\n\nHer sound blends IDM-inspired textures, dubstep-influenced bass pressure, deep techno and electro rhythms, mostly focused on hardware.\n\nAnna also shares her knowledge through workshops on modular synthesis, live performance, and visual art, opening up spaces for learning and artistic exchange. ANNA Z is a member of the Spandau20 family, a record label based in Berlin, Germany.\n\nAnna Z | Instagram\n\nPhoto credit: Fabiana Amato"}, {"event": "Aftershow w/ Acida Dominga + Sam Rouanet", "place": "Waldkater", "date": "2026-05-07", "time": "2026-05-07, 9:00 pm", "category": "evening", "url": "https://www.superbooth.com/en/events/details/aftershow-w-acida-dominga-sam-rouanet.html", "details": "Wrapping up the first day with Acida Dominga and Sam Rouanet in the beer garden next to the FEZ fountain."}, {"event": "The Abstract Earth", "place": "Main Entrance", "date": "2026-05-08", "time": "2026-05-08, 10:00 am–11:00 am", "category": "concert", "url": "https://www.superbooth.com/en/events/details/the-abstract-earth-2.html", "details": "For decades, Charles Matuschewski has been shaping the Berlin music scene as a pianist, keyboardist, trumpeter, and producer. His current project, “The Abstract Earth Solo works,” uniquely combines analog live acoustic improvisation with electronic soundscapes. The result is a fascinating sound laboratory that draws the listener into a flowing dialogue between jazz, electronic, soul, and neo-classical music.\n\nWebsite:\n\nwww.theabstractearth.com"}, {"event": "SooperRadio: Radio Woltersdorf & PiRadio", "place": "SooperRADIO", "date": "2026-05-08", "time": "2026-05-08, 10:00 am", "category": "radio", "url": "https://www.superbooth.com/en/events/details/sooperradio-radio-woltersdorf-piradio-3.html", "details": "is our live radio format from the Superbooth team. We´ve now been broadcasting for over 4 years as part of the Radio Woltersdorf program in Berlin and Potsdam on the frequency of the independent station Piradio.\n\nStarting on Thursday, May 7th, 2026 we will broadcast LIVE from the Superbooth!\n\n24 hours of nerdtalk, gossip, education, madness - directly from the Pionierpalast to your radio.\n\nWe appreciate the participatory approach of everyone involved in the event and are looking forward to the musically rich program (check the line-up!!!).\n\nSo tune in your radios and remember: \"Every ten minutes a person falls in love with a modular system\" (A. Schneider)..\n\nRadio frequency 88.4 MHz in Berlin or in Potsdam on 90.7 MHz or via live-stream on piradio.de"}, {"event": "Ambient Dub Café till noon", "place": "Sooper Corner", "date": "2026-05-08", "time": "2026-05-08, 10:00 am–12:00 pm", "category": "ambient", "url": "https://www.superbooth.com/en/events/details/ambient-dub-cafe-till-noon-3.html", "details": "The mono-chill ambient sounds are back for SB26 – on the Super-Power Sound System every morning until noon. Grab a coffee and relax with the Berlin Dubcafé crew."}, {"event": "DIY Workshop - Touellskouarn", "place": "DIY-Area", "date": "2026-05-08", "time": "2026-05-08, 11:00 am–2:00 pm", "category": "diy", "url": "https://www.superbooth.com/en/events/details/diy-workshop-touellskouarn-2.html", "details": "Strakal Orsel (Tube distortion) /// DIY Level: Easy /// Price: 180€\n\nSonveskañ (Germ. Mixer Dist. Feedb.) /// DIY Level: Easy /// Price: 200€\n\nStrakal Silisiom (Stereo Fuzz Feedb.) /// DIY Level: Medium /// Price: 150€\n\nAr Merc’Het Brao (Dual Lo/Hi Filter, Oververdr.) /// DIY Level: Easy /// Price: 250€\n\nHeklev (BBD Analog Rev, Flanger) /// DIY Level: Medium /// Price: 180€\n\nJoin Touellskouarn and build one of their Eurorack distortions and FX while exploring different flavours of drive: germanium, silicon and tubes."}, {"event": "DIY Workshop - Error Instruments", "place": "DIY-Area", "date": "2026-05-08", "time": "2026-05-08, 11:00 am–2:00 pm", "category": "diy", "url": "https://www.superbooth.com/en/events/details/diy-workshop-error-instruments-2.html", "details": "Das Ritual /// DIY Level: Easy /// Price: 135€\n\nThe Ritual is a standalone device that turns the movement of a flame into sound. It features two sound engines: one crisp and noisy, the other smooth like a sine wave, reminiscent of a theremin. It also includes Eurorack-compatible CV inputs."}, {"event": "Modular Beginner Workshop", "place": "Kino", "date": "2026-05-08", "time": "2026-05-08, 11:00 am–12:00 pm", "category": "workshop", "url": "https://www.superbooth.com/en/events/details/modular-beginner-workshop-5.html", "details": "Modular Beginner Workshop for all\n\nWe will cover the essential topics and basic vocabulary necessary to understand the principles of synthesis and patching. Join us and and we’ll help you be on your way to navigating the world of modular synthesis.\n\nAll are welcome and there is no booking required for this workshop .\n\nThis workshop will be held in English."}, {"event": "FLINTA* for Modular Beginners", "place": "Flinta*Area", "date": "2026-05-08", "time": "2026-05-08, 11:00 am–12:00 pm", "category": "flinta", "url": "https://www.superbooth.com/en/events/details/flinta-for-modular-beginners.html", "details": "FLINTA* workshops are exclusively for women, trans, non-binary, and gender-expansive people.\n\nOur yearly introductory workshop for FLINTA* (women, trans, non-binary, and gender-expansive people) is intended as an opportunity to learn more about the world of modular synthesis in a relaxed and inclusive atmosphere.\n\nThe workshop on Friday will be hosted by Neon Black Cat. Line, aka Neon.Black.Cat, is a trained designer and has also been a musician for over 20 years. After her time in punk rock, she discovered the world of synthesizers four years ago. Since then, she has been performing live regularly and co-founded the collective “Die Patcherei” with like-minded people, organizing regular synth jams in Bremen. Since 2024, she has also been giving workshops on synthesizers and drum machines through the FLINTA* collective “Mausalarm.” Her goal is to make it easier—especially for younger generations—to enter what is often perceived as a “male-dominated” field.\n\nPlease note: To enter the workshop you need a Superbooth ticket for the the day (or a 3-day ticket) + the free of charge workshop ticket itself. Both Tickets are vailable HERE in our ticket shop.\n\nThis workshop will be held in English"}, {"event": "Sonia Killmann", "place": "Seebühne", "date": "2026-05-08", "time": "2026-05-08, 11:00 am–11:40 am", "category": "concert", "url": "https://www.superbooth.com/en/events/details/sonia-killmann.html", "details": "Sonia Killmann is an international saxophone player and electronic musician. They have performed across the UK and Europe and are collaborating closely with Cryptic Glasgow as a Cryptic artist, working in immersive installations and audiovisual performance.\n\nSonia's work merges organic and synthetic sound worlds by combining field recording, saxophone, and modular synthesis to create abstract soundscapes. Sonia has been exploring Pauline Oliveros’ Deep Listening concepts through circular breathing and adapting environments in the context of live performance. In 2025, Sonia won the Lumen Prize together with Laura Mannelli for music and performance with the installation Umweltraum(a).\n\nSonia Killmann | Bandcamp"}, {"event": "Tony Miln", "place": "Sooper Corner", "date": "2026-05-08", "time": "2026-05-08, 12:40 pm–2:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/tony-miln.html", "details": "Tony is Head Gear Head at Soundgas, a UK manufacturer, restorer and supplier of vintage and vintage-inspired studio gear and instruments.  He worked as a DJ from 1991-2013 playing all over the UK and Europe before 'retiring' to concentrate on studio work and Soundgas.\n\nWith historic releases under various guises on Peace Feast Industries, Tummy Touch Records, Breakdown, and forthcoming new material via Soungdas Recordings.\n\nHis live studio dub workouts and remixes can be found on Instagram and Soundgas Bandcamp.\n\nExpect a heavily dub-infused mix of exclusive remixes as well as new music from Sound Mesters, Steve Edwards and Tony Soundgas.\n\nSoundgas | Instagram | Bandcamp"}, {"event": "Stromkult - In Conversation with Polygonia", "place": "Stromkult Stage", "date": "2026-05-08", "time": "2026-05-08, 1:00 pm–1:30 pm", "category": "talk", "url": "https://www.superbooth.com/en/events/details/stromkult-in-conversation-with-polygonia.html", "details": "For the first time this year, Stromkult , in collaboration with the SuperBooth and SchneidersLaden, is hosting a stage for conversations about electronic music and making electronic music in the cozy Bungalowdorf area of the SuperBooth. Rather than focusing on direct product demos, the idea behind this stage is to provide insight into the philosophies and working processes of the people behind the instruments – as well as the artists using them – through casual live conversation panels."}, {"event": "Surgeons Girl + Diego Nogueras + Oora", "place": "Seebühne", "date": "2026-05-08", "time": "2026-05-08, 1:00 pm–1:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/surgeons-girl-diego-nogueras-oora.html", "details": "At Superbooth 2026,  Surgeons Girl joins Diego Nogueras  and Oora for a unique collaborative performance centered around the iconic Vermona Perfourmer.\n\nWidely recognized for their deep and distinctive approaches to the instrument, the three artists bring their individual sonic identities into a shared framework built entirely on the Perfourmer’s four analog voices. The project reimagines the synthesizer not as a supporting tool, but as a complete and self-contained musical system.\n\nRooted in limitation as a creative principle, the performance explores texture, movement, and evolving harmonic structures through focused sound design and real-time interaction. Each artist’s relationship with the instrument shapes the collective result, revealing new dimensions of an already legendary synthesizer.\n\nThis special appearance highlights the expressive depth of a single instrument in the hands of dedicated artists, celebrating constraint as a catalyst for innovation."}, {"event": "Workshop - Bitwig", "place": "Workshop Room", "date": "2026-05-08", "time": "2026-05-08, 1:30 pm–2:30 pm", "category": "workshop", "url": "https://www.superbooth.com/en/events/details/workshop-bitwig-3.html", "details": "From Studio to Stage: Preparing Your Music for Live Performance with Bitwig Studio\n\nIn this session, we will explore how to set up and structure your live set in Bitwig Studio, arrange your tracks for performance, and integrate hardware into your setup. Find out how to turn your music productions into your first live performance."}, {"event": "Modular Synthesizer Ensemble", "place": "Auditorium", "date": "2026-05-08", "time": "2026-05-08, 1:30 pm–1:50 pm", "category": "workshop", "url": "https://www.superbooth.com/en/events/details/modular-synthesizer-ensemble-12.html", "details": "The result of a 4-hour workshop with school students will be presented. From 9 a.m. to 1 p.m. they will patch, experiment, improvise and work on a composition together.\n\nThe MODULAR SYNTHESIZER ENSEMBLE shows impressively that it is also possible to make music together with 12 modular synthesizers. The project enables immediate and intuitive access to electronic music even without any previous knowledge and is therefore open to everyone.\n\nThe project format was developed by Gammon, in cooperation with two Viennese schools, before it was presented for the first time during Superbooth 2017. \"The essential thing for me is the shared musical process and the sensual experience in the group. From the first cable connection to the live performance without any previous knowledge. But even for the experienced, it is an exciting challenge to play together in a larger group.\" says Gammon."}, {"event": "Die Stadt der Zukunft", "place": "Strandbühne", "date": "2026-05-08", "time": "2026-05-08, 2:00 pm–2:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/die-stadt-der-zukunft.html", "details": "Die Stadt der Zukunft – „the city of the future“ is made of vibrations.\n\nIt started with a hybrid guitar called Techtar. This instrument resembles an electric guitar—its six strings are automatically plucked by actuators, while the frets are fretted by hand. Then there's the robot bass called Pythagotron, a stretched string on which a carriage moves up and down; the string is plucked by a motor, and another motor determines the pitch. The third instrument has no name—it's a mechatronic harp that conjures triads, three strings, three ways to automatically set them in motion, four frets.\n\nFrank Piesik, Alex Böll, and Gregor Hennig operate these machines and distort their sounds with all sorts of things; the music is improvised, hypnotic, compelling. If this is the city of the future, perhaps there is still hope.\n\nBandcamp"}, {"event": "C&D - Piotr Ceglarek and Jan Dybala", "place": "Tonarium/Studiobühne", "date": "2026-05-08", "time": "2026-05-08, 2:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/c-d-piotr-ceglarek-and-jan-dybala.html", "details": "C&D – Piotr Ceglarek and Jan Dybala are an experimental duo from Katowice, Poland, working somewhere between new media arts, the concert stage, and a buzzing cable jungle. In 2014, they co-founded Biuro Dźwięku Katowice, a socially engaged platform dedicated to sound experiments, education, and the use of a homegrown multichannel sound system.\n\nA few years later, they introduced similar practices at the local Academy of Fine Arts, building on their ongoing work there through a new collaboration with the Soundscape Foundation. Together, they helped create Tonarium: a hybrid spatial sound instrument embedded in a large 36-channel listening space.\n\nTheir live shows are rare but always site-specific and managed in real time. Besides many strictly local events, C&D appeared at Nachtdigital (2017), Unsound Festival (2015), Sanatorium of Sound (2017–2025), and Tauron Nowa Muzyka Festival (2016–2022).\n\nThe performance takes place as part of the Tonarium exhibition.\n\nPiotr Ceglarek | Jan Dybala"}, {"event": "Gesprächskonzert - Nonlinear Labs", "place": "Kino", "date": "2026-05-08", "time": "2026-05-08, 2:30 pm–2:50 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/gespraechskonzert-nonlinear-labs-4.html", "details": "Tim Sund will perform on the new synthesizer from Nonlinear Labs with his trio ELECTRIFIED (Alex Will on bass, Jonathan Gradmann on drums). Nonlinear Labs' founder Stephan Schmitt will explain the concept behind the instrument."}, {"event": "Snow", "place": "Sooper Corner", "date": "2026-05-08", "time": "2026-05-08, 2:40 pm–4:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/snow.html", "details": "Romy Pope studied cultural science with a focus on electronic music. She appears both behind the scenes and in the spotlight. As a DJ booker, radio producer, and event organizer, she has been working in various agencies and clubs for years. But she enjoys getting behind the DJ booth just as much. Her own partyseries, SATURNITE, has been running for 20 years at the Golden Pudel Club in Hamburg. There is hardly a club in Berlin where she hasn't dj-ed as Snow. Her musical style is wide-ranging, with a penchant for concise basslines, varied beats, and subtle disco arrangements.\n\nInstagram | Soundcloud | RA\n\nPhoto credit: Alana Naumann"}, {"event": "Stromkult - In Conversation with Verbos Electronics", "place": "Stromkult Stage", "date": "2026-05-08", "time": "2026-05-08, 3:00 pm–3:30 pm", "category": "talk", "url": "https://www.superbooth.com/en/events/details/stromkult-in-conversation-with-verbos-electronics.html", "details": "For the first time this year, Stromkult , in collaboration with the SuperBooth and SchneidersLaden, is hosting a stage for conversations about electronic music and making electronic music in the cozy Bungalowdorf area of the SuperBooth. Rather than focusing on direct product demos, the idea behind this stage is to provide insight into the philosophies and working processes of the people behind the instruments – as well as the artists using them – through casual live conversation panels."}, {"event": "DIY Workshop - Bastl Instruments", "place": "DIY-Area", "date": "2026-05-08", "time": "2026-05-08, 3:00 pm–6:00 pm", "category": "diy", "url": "https://www.superbooth.com/en/events/details/diy-workshop-bastl-instruments.html", "details": "Kastle 2 /// DIY Level: Easy /// Price: 130€\n\nJoin us at Superbooth for a DIY soldering workshop featuring the Kastle 2  from Bastl Instruments. You can choose one of the 3 variants: Alchemist (hybrid-synthesis), Wave Bard (stereo sample player) and FX Wizard (stereo multi-effect) - please specify by email after registration (see further down).\n\nNo deep soldering skills required. The main board comes pre-soldered with SMT parts so all you need to do is solder a few components and assemble the unit. Our team will guide you through the process step by step. Walk away with your own fully assembled Kastle 2 - ready to bend sound in ways you never imagined."}, {"event": "DIY Workshop - Shakmat", "place": "DIY-Area", "date": "2026-05-08", "time": "2026-05-08, 3:00 pm–6:00 pm", "category": "diy", "url": "https://www.superbooth.com/en/events/details/diy-workshop-shakmat-4.html", "details": "Archer’s Rig /// DIY Level: Medium /// Price: 190€\n\nBattering Ram /// DIY Level: Easy /// Price: 180€\n\nClock'O Pawn mk2 /// DIY Level: Medium /// Price: 130€\n\nHarlequin's Context /// DIY Level: Medium /// Price: 200€\n\nJeweler's Cast /// DIY Level: Easy /// Price: 110€\n\nBuild your Shakmat DIY kit together with the Shakmat team. You get help throughout the entire workshop and take home a fully working module!"}, {"event": "Panic Girl", "place": "Seebühne", "date": "2026-05-08", "time": "2026-05-08, 3:00 pm–3:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/panic-girl.html", "details": "Panic Girl is a composer, music producer, and synthesizer sound designer with a passion for electronic music and a distinctive collection of analog gear. Classically trained in piano, guitar, and singing, she crafts music for broadcasting, film, and advertising, working with clients such as Netflix, Moog Music, Spitfire Audio, and the German broadcasting station Bayerischer Rundfunk, among others. Always on the lookout for extraordinary and unconventional sounds, her work showcases a deep commitment to innovation and sonic exploration.\n\nPanic Girl | Instagram | Bandcamp"}, {"event": "FLINTA* Workshop - An On Bast: Hardware Live Setups", "place": "Flinta*Area", "date": "2026-05-08", "time": "2026-05-08, 3:00 pm–4:00 pm", "category": "flinta", "url": "https://www.superbooth.com/en/events/details/flinta-workshop-shaping-your-hardware-live-set.html", "details": "FLINTA* workshops are exclusively for women, trans, non-binary, and gender-expansive people.\n\nDesign a modular synthesizer system that truly serves your live performance.\n\nThis workshop explores how to shape your modular setup from initial concept to stage-ready execution. We will move from artistic intention to practical realization, examining system design, voice architecture, movement, flexibility and performance flow. You will learn how to build multi-voice patches and create dynamic transitions, and how to balance structure and improvisation.\n\nWe will also dive into ergonomic patching strategies - how to design a system that feels intuitive and playable in a live context: how to keep control, clarity and expression while standing on stage.\n\nIn addition, we will discuss the role of external hardware instruments and how they can complement your modular system. The goal is not just a functioning setup but a performance instrument that is expressive, flexible and deeply personal, that amplifies your artistic vision.\n\nThis workshop will be held in English .\n\nPlease note: To enter the workshop you need a Superbooth ticket for the the day (or a 3-day ticket) + the workshop ticket itself. Both Tickets are vailable HERE in our ticket shop."}, {"event": "Workshop - DSP-Dealer", "place": "Workshop Room", "date": "2026-05-08", "time": "2026-05-08, 3:30 pm–5:00 pm", "category": "workshop", "url": "https://www.superbooth.com/en/events/details/workshop-dsp-dealer-2.html", "details": "In this workshop, FTP Doctor (Musician & Live Sound Engineer) presents the professional application of Inspect—an advanced audio analysis software developed by DSP Dealer—within live sound and mastering environments.\n\nThrough practical examples, the workshop demonstrates how this precise metering tool drastically simplifies the daily workflow at both the FOH console and in the studio, while significantly speeding up processes. FTP Doctor explores how visual audio analysis empowers engineers to make informed technical decisions regarding frequency balance, dynamics, and loudness. Attendees will discover how the software serves as a reliable tool that reveals acoustic details in real time, ultimately helping to consistently achieve highly musical results with much greater ease."}, {"event": "Gesprächskonzert - FRAKnoise", "place": "Kino", "date": "2026-05-08", "time": "2026-05-08, 3:30 pm–3:50 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/gespraechskonzert-fraknoise.html", "details": "Following last year’s Lectute concert, this session revisits the world of the Melancholytron — exploring the nature of melancholy through images, sound, and narrative. Selected visuals from the Melancholytron book will be paired with live sonic demonstrations, offering insight into the instrument’s conceptual and emotional landscape.\n\nThe current version, including the desktop model, will also be introduced, outlining key differences and upcoming availability.\n\nThe presentation concludes with a short live performance incorporating analog playback elements. Time permitting, there will be an opportunity for questions — and further discussion can continue at the booth."}, {"event": "Jessica Kert", "place": "Strandbühne", "date": "2026-05-08", "time": "2026-05-08, 4:00 pm–4:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/jessica-kert-4.html", "details": "Jessica Kert is a modular synth connoisseur who’s become known across the globe in recent years for her intricate, psychedelia infused, murky Techno style which has found a home on imprints such as Detroit Underground, Atmophile Electronics and Associated Paraboloid. On top of her regular work at Berlin synth haven SchneidersLaden. Jessica also does many workshops exclusively for the women, trans, inter & nonbinary community.\n\nInstagram | Bandcamp | RA"}, {"event": "biøs- Jakub Mokrzysiak", "place": "Tonarium/Studiobühne", "date": "2026-05-08", "time": "2026-05-08, 4:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/bios-jakub-mokrzysiak.html", "details": "Jakub Mokrzysiak – a producer, DJ, and sound engineer based in Silesia. Artistic Director of the Soundscape Foundation and sound director at Tonarium – the Laboratory of New Media. He is involved in teaching and workshop activities focused on sound editing, and has collaborated with institutions such as Medialab Katowice, WSTI, and the Wawel jest Wasz Festival. As an artist and curator, he develops projects that combine musical practice, education, and new technologies, supporting the growth of Poland’s experimental and electronic music scene.\n\nThe performance takes place as part of the Tonarium exhibition.\n\nInstagram | Bandcamp"}, {"event": "Gesprächskonzert - Tubbutec", "place": "Kino", "date": "2026-05-08", "time": "2026-05-08, 4:30 pm–4:50 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/gespraechskonzert-tubbutec.html", "details": "Rob Ellis, aka Robot Man Machine (RMM), presents the Tubbutec Brainstep sequencer and demonstrates how he integrates it into his live modular setup.\n\nYou’ll also experience how the Brainstep Expander transforms it into a powerful modulation generator.\n\nTobi from Tubbutec will explain a few details about the setup and the Brainstep in general."}, {"event": "Perera Elsewhere", "place": "Sooper Corner", "date": "2026-05-08", "time": "2026-05-08, 4:40 pm–6:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/perera-elsewhere.html", "details": "Multi-award-winning experimental pop artist Sasha Perera aka Perera Elsewhere is a producer, musician, songwriter and DJ acclaimed by Pitchfork, NPR, BBC, FADER, Vogue and KCRW.\n\nBlending voice, trumpet, bass and sound design with existential themes, she developed the sound early press dubbed “Doom-Folk.” On LA label Friends of Friends, she released three albums marking a steady sonic evolution, drawing comparisons to Mica Levi, Dean Blunt, Jon Hassell and Massive Attack.\n\nHer path runs from London’s club scene to Berlin’s experimental underground, shaping a fluid, genre-defying approach. She has performed and DJed at Berghain, the Guggenheim, Hamburg Philharmonic, Sónar and Boiler Room.\n\nHer music has been licensed for Ava DuVernay’s Queen Sugar, Paolo Sorrentino’s Loro, and Apple’s M2 campaign. She also composes for film, theatre and audiovisual works, including projects for Bass Museum Miami (2022) and ZKM Karlsruhe (2024).\n\nAlongside her solo work, she has worked with and produced for artists including Nina Hagen (four songs on her 2023 album). She won “Best Act” at the VIA Awards 2022 and received Sony Music Germany’s Female Producer Award in 2024. Perera also leads workshops and mentoring for Ableton, Native Instruments, Yale and Berlin University of the Arts, and collaborates internationally with the British Council and Goethe-Institut.\n\nPerera Elsewhere"}, {"event": "Stromkult - In Conversation with Eowave", "place": "Stromkult Stage", "date": "2026-05-08", "time": "2026-05-08, 5:00 pm–5:30 pm", "category": "talk", "url": "https://www.superbooth.com/en/events/details/stromkult-in-conversation-with-eowave.html", "details": "For the first time this year, Stromkult , in collaboration with the SuperBooth and SchneidersLaden, is hosting a stage for conversations about electronic music and making electronic music in the cozy Bungalowdorf area of the SuperBooth. Rather than focusing on direct product demos, the idea behind this stage is to provide insight into the philosophies and working processes of the people behind the instruments – as well as the artists using them – through casual live conversation panels."}, {"event": "Monolake", "place": "Seebühne", "date": "2026-05-08", "time": "2026-05-08, 5:00 pm–5:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/monolake.html", "details": "Monolake (Robert Henke) is an artistic toolmaker, creating music, audiovisual performances, installations, and computer graphics. His work ranges from concerts and compositions to large-scale, technology-driven installations, often built around custom-developed algorithms and machines. As Monolake, he explores the physical force of techno and the refined textures of contemporary music, while his visual work draws on Minimal Art and early computer graphics. He was one of the main creators of Ableton Live and has collaborated with artists such as Marko Nikodijevic, Tarik Barri, and Christopher Bauder, presenting his work at institutions including Tate Modern and Centre Pompidou, as well as at major international festivals.\n\nRobert Henke | Bandcamp | Monolake 8bit"}, {"event": "Gesprächskonzert - Weston Precision Audio", "place": "Kino", "date": "2026-05-08", "time": "2026-05-08, 5:30 pm–5:50 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/gespraechskonzert-weston.html", "details": "Join Trovarsi and Devin of Weston Precision Audio to introduce TRIVIUM, their Eurorack module collaboration.\n\nThe session opens with a breakdown of the module: what it is, how it works, and the vision behind its design. Together, they will walk through TRIVIUM’s architecture as a complete voice (minus the oscillator), highlighting its filter, dual envelopes, and performance-focused modulation.\n\nThe second half transitions into a 10-minute live set by TROVARSI, showcasing TRIVIUM in action through a raw, hands-on performance built for real-time control."}, {"event": "M. Takara & Carla Boregas", "place": "Strandbühne", "date": "2026-05-08", "time": "2026-05-08, 6:00 pm–6:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/m-takara-carla-boregas.html", "details": "Both crucial members of the Brazilian music scene, Carla Boregas and M.Takara have been playing as a duo since 2018. Together their music is the result of an interplay between drums and synths, blending Boregas’s aether and warmth electronics with Takara’s jazzy improvised percussion, somewhere between abstract improvisation and propulsive rhythm. The landscape they present is real and vibrant, sometimes brash, sometimes beautiful, rarely bland or ambivalent, an organic layering of manipulated synthesizers and acoustic sounds.\n\nFirst linking minds on 2020’s \"Linha D'Água\" (Bokeh Versions), where they attempted to sounding the abstract and succeed in creating a mysterious and evocative soundtrack with water as a central element of inspiration. The aquatic theme is still present on the new release \"Grande Massa D'Água\" (Hive Mind Records). The dubbed-out, dreamlike gravity that anchored their debut was replaced by finely cracked filigree constructions that sound as if they might shatter at any moment, slipping through the cracks just like the water that informs their compositional process, coating the past and gushing forcefully into the future. From the fringes of jazz, electroacustic and electronica, they pour that experience into the immersive.\n\nInstagram - Carla Boregas | Instagram - M Takara"}, {"event": "Murat Tepeli", "place": "Sooper Corner", "date": "2026-05-08", "time": "2026-05-08, 6:40 pm–8:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/murat-tepeli.html", "details": "Murat Tepeli’s craft is balance: as a DJ and producer, he moves effortlessly between ecstasy and elegance, physical drive and emotional depth. Since starting out in the mid-’90s with a wide spectrum of influences—from hip-hop to drum & bass—house music gradually became his foundation, enriched by diverse sounds spanning synthpop to oriental textures. His productions mirror this duality, pairing melancholy with dancefloor urgency, reduction with opulence. With releases on labels like Playhouse, Ostgut Ton, and Philpot, as well as his collaborative album Serenity with Prosumer, Tepeli has helped shape modern house music.\n\nRA | Ostgut"}, {"event": "Anushka Chkheidze", "place": "Seebühne", "date": "2026-05-08", "time": "2026-05-08, 7:00 pm–7:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/anushka-chkheidze.html", "details": "Anushka Chkheidze is a Georgian composer and sound artist, born in Tbilisi in 1997. Her multifaceted work ranges from immersive soundscapes integrating field recordings, choir voices, and organ music to more rhythmically driven compositions. Since her debut album Halfie (2020), followed by Move 20-21 , Lost Luggage , and Clean, Clear and White , she has developed a distinctive sonic language that transforms spaces into poetic, site-specific experiences.\n\nShe has performed at international festivals and exhibitions including the Darmstädter Ferienkurse, Close Encounters Festival, and the Monheim Triennale, which commissioned her to create site-specific works such as Intricate Pipes , a composition for MIDI organ and analog setups that premiered in 2025. Installations including Lost Lullaby and See Me blend local voices, environmental recordings, and instrumental textures to explore memory, place, and social interaction through immersive sound.\n\nAnushka Chkheidze has collaborated with artists including Robert Lippok, Eto Gelashvili, Hayk Karoyi, and Lillevan Pobjoy, focusing on real-time composition and the interplay between classical and electronic elements.\n\nAnushka Chkheidze | Instagram\n\nPhoto Credit: Levan Maisuradze"}, {"event": "Polygonia", "place": "Strandbühne", "date": "2026-05-08", "time": "2026-05-08, 8:00 pm–8:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/polygonia-2.html", "details": "Polygonia is a multidisciplinary music and art project by Munich-based artist Lindsey Wang. Drawing from a background in acoustic instruments and a strong interest in cultural diversity, she creates colourful electronic music enriched with complex sound design and intricate yet compelling rhythms.\n\nHer work is defined by a dynamic fusion of genres, resulting in a distinctive sound that moves beyond fixed categorisation. Elements of techno, bass music, breakbeat, house, electro, grey area, IDM and beyond intertwine throughout her productions. This genre-fluid approach is evident in releases such as her 2025 album Dream Horizons on Dekmantel and the Otro Mundo EP (2023) on Bambounou’s Bambe label, while nature continues to serve as a recurring source of inspiration.\n\nIn both DJ and live sets, Polygonia explores a wide emotional spectrum, adapting her performances to time and atmosphere. She has played numerous renowned venues and is a regular at Tresor and Berghain, while also holding a residency at Munich’s BLITZ club since 2023.\n\nBeyond her solo work, she co-founded the IO collective and label in 2018 and launched her own label QEONE in 2022. In 2021, she formed the electric jazz trio Lyder and continues to explore the intersection of electronic and jazz through her collaboration with drummer Simon Popp. In 2025, she also co-founded the audio software company DSP Dealer.\n\nRA | Instagram | Bandcamp | Soundcloud\n\nPhoto credit: Fan Wen"}, {"event": "Aftershow w/ lil.lili + Resom b2b Don Williams", "place": "Waldkater", "date": "2026-05-08", "time": "2026-05-08, 9:00 pm", "category": "evening", "url": "https://www.superbooth.com/en/events/details/aftershow-w-lil-lili-resom-b2b-don-williams.html", "details": "Last rounds at the beer garden to the right of the FEZ fountain. We're excited that our good friends lil.lili and Resom and Don Williams will be taking over the aftershow party on Friday – with danceable music and good vibes for a perfect way to end the evening."}, {"event": "The Abstract Earth", "place": "Main Entrance", "date": "2026-05-09", "time": "2026-05-09, 10:00 am–11:00 am", "category": "concert", "url": "https://www.superbooth.com/en/events/details/the-abstract-earth-kopie-2.html", "details": "For decades, Charles Matuschewski has been shaping the Berlin music scene as a pianist, keyboardist, trumpeter, and producer. His current project, “The Abstract Earth Solo works,” uniquely combines analog live acoustic improvisation with electronic soundscapes. The result is a fascinating sound laboratory that draws the listener into a flowing dialogue between jazz, electronic, soul, and neo-classical music.\n\nWebsite:\n\nwww.theabstractearth.com"}, {"event": "SooperRadio: Radio Woltersdorf & PiRadio", "place": "SooperRADIO", "date": "2026-05-09", "time": "2026-05-09, 10:00 am", "category": "radio", "url": "https://www.superbooth.com/en/events/details/sooperradio-radio-woltersdorf-piradio-4.html", "details": "is our live radio format from the Superbooth team. We´ve now been broadcasting for over 4 years as part of the Radio Woltersdorf program in Berlin and Potsdam on the frequency of the independent station Piradio.\n\nStarting on Thursday, May 7th, 2026 we will broadcast LIVE from the Superbooth!\n\n24 hours of nerdtalk, gossip, education, madness - directly from the Pionierpalast to your radio.\n\nWe appreciate the participatory approach of everyone involved in the event and are looking forward to the musically rich program (check the line-up!!!).\n\nSo tune in your radios and remember: \"Every ten minutes a person falls in love with a modular system\" (A. Schneider)..\n\nRadio frequency 88.4 MHz in Berlin or in Potsdam on 90.7 MHz or via live-stream on piradio.de"}, {"event": "Ambient Dub Café till noon", "place": "Sooper Corner", "date": "2026-05-09", "time": "2026-05-09, 10:00 am–12:00 pm", "category": "ambient", "url": "https://www.superbooth.com/en/events/details/ambient-dub-cafe-till-noon-4.html", "details": "The mono-chill ambient sounds are back for SB26 – on the Super-Power Sound System every morning until noon. Grab a coffee and relax with the Berlin Dubcafé crew."}, {"event": "DIY Workshop - Erica & Moritz Klein", "place": "DIY-Area", "date": "2026-05-09", "time": "2026-05-09, 11:00 am–2:00 pm", "category": "diy", "url": "https://www.superbooth.com/en/events/details/diy-workshop-mkl-x-erica-synths.html", "details": "How Does a VCO Work? A Circuit Design Workshop /// DIY Level: Easy /// Price: 110€\n\nIn this beginner-friendly workshop, you'll not only explore a fully-functioning VCO core on a LABOR prototyping board – you'll also gain an in-depth understanding of how it works. For that, Moritz Klein will guide you through the basics of analog circuit design, providing you with practical skills that you can apply to your own circuit design projects.\n\nDon't have any components yet? No worries! Every participant will receive a full mki x es.edu DIY VCO kit, so you can continue experimenting at home. And once you're ready, you can even assemble the VCO into a proper Eurorack module using the included PCB and panel."}, {"event": "DIY Workshop - ATOV", "place": "DIY-Area", "date": "2026-05-09", "time": "2026-05-09, 11:00 am–2:00 pm", "category": "diy", "url": "https://www.superbooth.com/en/events/details/diy-workshop-atov.html", "details": "Faderpunk /// DIY Level: Medium/Advanced /// Price: 530€\n\nLX-Euclid /// DIY Level: Easy /// Price: 230€ (black)\n\ncDVCA /// DIY Level: Easy /// Price: 170€ (black / silver)\n\ncLFO /// DIY Level: Easy /// Price: 230€  (black / silver)\n\nMMx2 /// DIY Level: Easy /// Price: 130€ (black)\n\nCome and build one of the ATOV kits with the designer in person. Please contact us at info@atov.de and let us know which kit(s) and panel colour you'd like so we can make sure to bring yours.\n\nFaderpunk is a modulation ecosystem built around 16 faders, running up to 16 simultaneous apps such as LFOs, sequencers, CV/MIDI utilities, quantizers, and more. Open-source firmware with a growing community app library.  The Faderpunk DIY kit is not available through any retailer and is unlikely to be offered outside of DIY workshops. Assembled it retails at 650€ build your own for 530€. https://faderpunk.cv/\n\nLX-Euclid is a 4-channel Euclidean trigger sequencer with two touch-sensitive rings and a full-colour circular display. The rings make mutes, fills, and resets immediately accessible for fast, real-time performance. Features 4 assignable CV inputs, probability settings, 8 save slots, Exponential and Mirrored Euclidean algorithms, and a burst generator. https://atov.de/products/lx-euclid\n\ncDVCA is a waveshaper, VCA, and a filter. It is the first and only Class D VCA in Eurorack. It can function as an oscillator, waveshaper, distortion, filter, and even a small synth voice, all in a compact 6HP. https://atov.de/products/cdvca\n\ncLFO is a complex dual LFO designed with a focus on self- and cross-patching between the two LFOs, producing a wide range of evolving modulations. Also features a ring modulator an unusual addition for generating modulations that never quite repeat. https://atov.de/products/clfo\n\nMmx2 is a bundle of two MM mixer modules that can be used individually or chained into a larger matrix mixer. The first two inputs are attenuated, the last two have attenuverters, making it a versatile tool for distributing modulation, building sends, creating stereo effects, and much more. https://atov.de/products/mmx2"}, {"event": "Andrea Cichecki", "place": "Seebühne", "date": "2026-05-09", "time": "2026-05-09, 11:00 am–11:40 am", "category": "concert", "url": "https://www.superbooth.com/en/events/details/andrea-cichecki.html", "details": "Andrea Cichecki creates Synths, Sounds, and Noise that are as magical as they are modern.\n\nNestled in her countryside studio with her self-built modular Eurorack synthesizer, Andrea is a composer and sound artist who creates her signature sound by layering analog and digital synth waves with influences from her natural surroundings. Her soundtracks and soundscapes are immersive pieces that transcend mainstream electronic music, blending her expertise in synthesis with organic noise and textures to compose emotional, transfixing music that invites listeners into her world.\n\nFor over 20 years, Andrea Cichecki has let her passion for music lead the way, taking her through ambient, experimental, and contemporary genres. Her versatility has led her to collaborate with filmmakers and artists, bringing stories in film and art to life through sound, including the score for the critically acclaimed and award-nominated short film 'Reclaiming Dragons' . She has released over a dozen singles and EPs and her album 'Drawn Into The Edge Effect' received a nomination on the long list of the prestigious German award 'Preis der Deutschen Schallplattenkritik' .\n\nAlongside her recorded work, Andrea performs live as a solo artist, and as a member of an audiovisual performance project with French painter Oilhack.\n\nWebsite | Instagram | Bandcamp | Youtube | Facebook"}, {"event": "Modular Beginner Workshop", "place": "Kino", "date": "2026-05-09", "time": "2026-05-09, 11:00 am–12:00 pm", "category": "workshop", "url": "https://www.superbooth.com/en/events/details/modular-beginner-workshop-4.html", "details": "Modular Beginner Workshop for all\n\nWe will cover the essential topics and basic vocabulary necessary to understand the principles of synthesis and patching. Join us and and we’ll help you be on your way to navigating the world of modular synthesis.\n\nAll are welcome and there is no booking required for this workshop .\n\nThis workshop will be held in English."}, {"event": "Alexander Spree - Meet Dr. Spree", "place": "Strandbühne", "date": "2026-05-09", "time": "2026-05-09, 11:00 am–12:30 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/alexander-spree-meet-dr-spree.html", "details": "For this event, Alexander Spree will present a 1.5-hour live format of his YouTube channel. The audience can watch him work live, ask questions, learn more about modular music and electronic production, and experience the creation of his live sets up close.\n\nAlexander Spree is a Berlin-based techno artist and classically trained clarinetist who, as co-founder of AEOX and through his modular live sets, interdisciplinary sound research projects, and internationally recognized YouTube channel, uniquely combines techno, sound art, and education. His releases include labels such as Ostgut Ton, Scandinavia, Null Records, Neue Heimat, Mental Ind., and many more. He has performed live in renowned clubs including Tresor Berlin, Ostgut, Panoramabar, Watergate, 1040 Leipzig, Cube X Düsseldorf, and at festivals such as Ferropolis, Hirschbar Open Air, and Superbooth Berlin.\n\nYoutube | Alexander Spree"}, {"event": "Modular Beginner Workshop for FLINTA*", "place": "Flinta*Area", "date": "2026-05-09", "time": "2026-05-09, 11:00 am–12:00 pm", "category": "flinta", "url": "https://www.superbooth.com/en/events/details/modular-beginner-workshop-for-flinta-2.html", "details": "FLINTA* workshops are exclusively for women, trans, non-binary, and gender-expansive people.\n\nOur yearly introductory workshop for FLINTA* (women, trans, non-binary, and gender-expansive people) is intended as an opportunity to learn more about the world of modular synthesis in a relaxed and inclusive atmosphere.\n\nThe workshop on Saturday will be hosted by Sonia Killmann. Sonia Killmann is an international saxophone player and electronic musician. They have performed across the UK and Europe and are collaborating closely with Cryptic Glasgow as a Cryptic artist, working in immersive installations and audiovisual performance. Sonia's work merges organic and synthetic sound worlds by combining field recording, saxophone, and modular synthesis to create abstract soundscapes.\n\nPlease note: To enter the workshop you need a Superbooth ticket for the the day (or a 3-day ticket) + the free of charge workshop ticket itself. Both Tickets are vailable HERE in our ticket shop.\n\nThis workshop will be held in English"}, {"event": "Workshop - DSP-Dealer", "place": "Workshop Room", "date": "2026-05-09", "time": "2026-05-09, 12:30 pm–2:00 pm", "category": "workshop", "url": "https://www.superbooth.com/en/events/details/workshop-dsp-dealer-3.html", "details": "In this workshop, artist and producer Polygonia introduces the use of Inspect—an audio analysis software developed by her company DSP Dealer, which is also exhibiting at Superbooth—within the music production process. Through live demonstrations, she will share insights into her creative workflow and show how visual audio analysis can support and inform artistic decisions during sound design and composition. Using Inspect as a tool for observing and understanding sonic structures, Polygonia explores how analytical perspectives can become part of an intuitive and exploratory approach to making music."}, {"event": "Aysun", "place": "Sooper Corner", "date": "2026-05-09", "time": "2026-05-09, 12:40 pm–2:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/aysun.html", "details": "Based between Berlin and New York, Aysun works across radio, listening spaces, and collaborative projects. The sound leans warm and low - dubby weight, jazz-leaning details, hazy electronics unfolding without urgency. DJ sets often take shape as small conceptual pieces, built around a theme and punctuated with field recordings.\n\nPart of Cashmere Radio and 8Ball Radio, with releases on W133 Records and Low End Therapy Records, the approach favors atmosphere over spectacle.\n\nInstagram | Soundcloud"}, {"event": "Stromkult - Im Gespräch mit Doepfer Musikelektronik", "place": "Stromkult Stage", "date": "2026-05-09", "time": "2026-05-09, 1:00 pm–1:30 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/stromkult-im-gespraech-mit-doepfer-musikelektronik.html", "details": "For the first time this year, Stromkult , in collaboration with the SuperBooth and SchneidersLaden, is hosting a stage for conversations about electronic music and making electronic music in the cozy Bungalowdorf area of the SuperBooth. Rather than focusing on direct product demos, the idea behind this stage is to provide insight into the philosophies and working processes of the people behind the instruments – as well as the artists using them – through casual live conversation panels."}, {"event": "Philo Tsoungui", "place": "Seebühne", "date": "2026-05-09", "time": "2026-05-09, 1:00 pm–1:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/philo-tsoungui.html", "details": "Philo Tsoungui is a producer, composer, and drummer. She studied classical percussion in Munich and pop music in Mannheim. As a drummer, she has performed on stage with artists such as Fred again.., The Mars Volta, Disarstar, Paula Hartmann, Mine, Fatoni, and many others.\n\nAs a composer and sound artist, she has written music for several radio plays produced by ARD and created commissioned works for institutions including Haus der Kulturen der Welt ( metonymy//bloodline , 2024).\n\nThe diverse influences she encountered early on are clearly reflected in her own music: classical music, Cameroonian Bikutsi, as well as techno and early-2000s hardcore. Powerful drums and intricate beats meet melancholic harmonies. In her creative practice, Philo continuously searches for the quintessence of the mosaic shaped by growing up in a multicultural household.\n\nShe is a recipient of the Deutscher Jazzpreis in the drums category, a fellow of Beethovenfest Bonn, and currently a scholarship holder at Akademie Schloss Solitude and the Stiftung Arvore. In 2026, she will celebrate her debut as a film composer.\n\nInstagram\n\nPhoto credit: Clara Renner"}, {"event": "Modular Synthesizer Ensemble", "place": "Auditorium", "date": "2026-05-09", "time": "2026-05-09, 1:30 pm–1:50 pm", "category": "workshop", "url": "https://www.superbooth.com/en/events/details/modular-synthesizer-ensemble-11.html", "details": "This concert is result of a 4-hour workshop with kids and teenangers. From 9 a.m. to 1 p.m. they will patch, experiment, improvise and work on a composition together.\n\nThe MODULAR SYNTHESIZER ENSEMBLE shows impressively that it is also possible to make music together with 12 modular synthesizers. The project enables immediate and intuitive access to electronic music even without any previous knowledge and is therefore open to everyone.\n\nThe project format was developed by Gammon, in cooperation with two Viennese schools, before it was presented for the first time during Superbooth 2017. \"The essential thing for me is the shared musical process and the sensual experience in the group. From the first cable connection to the live performance without any previous knowledge. But even for the experienced, it is an exciting challenge to play together in a larger group.\" says Gammon."}, {"event": "Braintheft", "place": "Strandbühne", "date": "2026-05-09", "time": "2026-05-09, 2:00 pm–2:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/braintheft.html", "details": "Introducing Braintheft, the live dub duo from Dublin, based in Berlin. The duo have developed a sound that is deeply rooted in dub, while also incorporating elements of techno, D'n'B, and trip-hop. Their music is characterised by the intricate interplay between modular synthesizers and live drums, creating a sound that is both powerful and hypnotic.\n\nBraintheft"}, {"event": "Youtube Fan Meetup", "place": "Wald", "date": "2026-05-09", "time": "2026-05-09, 2:00 pm", "category": "special", "url": "https://www.superbooth.com/en/events/details/youtube-fan-meetup-2.html", "details": "With Bobeats and other creators\n\nMeet your favorite Synth Youtubers! A casual and nerdy hangout where you can say Hello to your favorite synth youtubers. Bobeats, Divkid, Mylar Melodies, Jorb, Nadia Struiwigh, Dave Mech, Oora and many more will be there. Come and talk synths and hang out! You´ll find us right next to the circus tent in the forest, area ZW ."}, {"event": "Gesprächskonzert - Ferry Island Modular", "place": "Kino", "date": "2026-05-09", "time": "2026-05-09, 2:30 pm–2:50 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/gespraechskonzert-ferry-island-modular.html", "details": "Ferry Island Modular designs instruments that trust you, allowing space within the synthesizer to explore and navigate. Chief Engineer Justin walks through the philosophy behind their instruments, while Metamyther brings it into sound."}, {"event": "Masa Saji", "place": "Sooper Corner", "date": "2026-05-09", "time": "2026-05-09, 2:40 pm–4:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/masahiko-saji.html", "details": "Masahiko Saji is a Japanese DJ and producer who has been living in Berlin since 2012. On his early musical journey, he explored various styles since the 2000s, until in 2009 he decided to dedicate himself to club music. Digging for new music quickly became his favorite routine, a practice he continues to this day. In the studio, he enjoys working with both modular and hardware synthesizers, shaping these sounds with classic analog drum machines and samplers.\n\nAnother major inspiration for him is the speaker craftsmanship of Basil Martion, whose sound has influenced his music with elements of jazz, hip hop, dub, and funk. He is also continually impressed by the diversity and uniqueness of Berlin’s club culture. To give back to this universe, Masa has been actively involved for years not only in the musical sphere but beyond as well.\n\nRA | Soundcloud"}, {"event": "Stromkult - In Conversation with WMD", "place": "Stromkult Stage", "date": "2026-05-09", "time": "2026-05-09, 3:00 pm–3:30 pm", "category": "talk", "url": "https://www.superbooth.com/en/events/details/stromkult-in-conversation-with-wmd.html", "details": "For the first time this year, Stromkult , in collaboration with the SuperBooth and SchneidersLaden, is hosting a stage for conversations about electronic music and making electronic music in the cozy Bungalowdorf area of the SuperBooth. Rather than focusing on direct product demos, the idea behind this stage is to provide insight into the philosophies and working processes of the people behind the instruments – as well as the artists using them – through casual live conversation panels."}, {"event": "DIY Workshop - Befaco", "place": "DIY-Area", "date": "2026-05-09", "time": "2026-05-09, 3:00 pm–6:00 pm", "category": "diy", "url": "https://www.superbooth.com/en/events/details/diy-workshop-befaco-4.html", "details": "A*B+C /// DIY Level: Medium /// Price: 115€\n\nMuxlicer /// DIY Level: Medium /// Price: 150€\n\nMIDI Thing v2 /// DIY Level: Medium /// Price: 240€\n\nST Mix /// DIY Level: Medium /// Price: 80€\n\nOutput /// DIY Level: Medium /// Price: 80€\n\nBuild your own module from our DIY kits together with the Befaco crew!\n\nIf possible, please bring your own tools, although we will have some available on-site just in case.\n\nIf you're interested in building a specific Befaco kit not listed, please let us know in advance and we’ll do our best to arrange it for you."}, {"event": "DIY Workshop - Music Thing Modular", "place": "DIY-Area", "date": "2026-05-09", "time": "2026-05-09, 3:00 pm–6:00 pm", "category": "diy", "url": "https://www.superbooth.com/en/events/details/diy-workshop-music-thing-modular.html", "details": "Workshop Computer /// DIY Level: Easy /// Price: 160€\n\nTom Whitwell from Music Thing Modular is one of the most celebrated DIY designers in Eurorack. This DIY workshop is perfect for beginners and we welcome everyone to come along.\n\nWorkshop Computer is a multi-function module which can be instantly changed with hot-swappable program cards. This is the beating heart of the larger Workshop System, transplanted into Eurorack!\n\nThe kit already includes Reverb, Turing Machine and USB MIDI cards, and also 4 blank cards – ready to fill with any of the dozens of interesting programs being made by a vibrant community of developers."}, {"event": "FLINTA* Workshop - Modular Beats: Sound Architecture for Drums", "place": "Flinta*Area", "date": "2026-05-09", "time": "2026-05-09, 3:00 pm–4:00 pm", "category": "flinta", "url": "https://www.superbooth.com/en/events/details/flinta-workshop-modular-beats-sound-architecture-for-drums-2.html", "details": "FLINTA* workshops are exclusively for women, trans, non-binary, and gender-expansive people.\n\nModular Beats: Sound Architecture for Drums\n\nIn this workshop for FLINTA*, artist Anna Z introduces participants to the world of rhythmic sound design with modular synthesizers.\n\nWorkshop topics:\n\n•  Sound as Material – Developing drum sounds with modular systems •  Rhythm as Space – Sequencing and structuring beats •  Variation and Interaction – Dynamic processes and modulations\n\nThis workshop is for anyone looking to dive deeper into the art of modular beat design and will be held in English.\n\nPlease note: To enter the workshop you need a Superbooth ticket for the the day (or a 3-day ticket) + the workshop ticket itself. Both Tickets are vailable HERE in our ticket shop."}, {"event": "Passepartout Duo", "place": "Seebühne", "date": "2026-05-09", "time": "2026-05-09, 3:00 pm–3:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/passepartout-duo.html", "details": "Passepartout Duo's work draws from a carefully selected palette of electro-acoustic textures and shapeshifting rhythms, created using an evolving ecosystem of self-made musical instruments. The group has been on a nearly continuous world tour ever since they began collaborating in 2015, and their experiences traveling have heavily influenced their unconventional creative process.\n\nIn 2024, they teamed up with KOMA Elektronik to release their instrument called the \"Chromaplane\", a collaboration which will also unveil a new synthesizer in 2026.\n\nPassepartout Duo is Nicoletta Favari and Christopher Salvito.\n\nPassepartout Duo | Instagram | Bandcamp"}, {"event": "Gesprächskonzert - SOMA", "place": "Kino", "date": "2026-05-09", "time": "2026-05-09, 3:30 pm–3:50 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/gespraechskonzert-soma-4.html", "details": "ENIGMA is an experimental synthesizer guided entirely by the position and movement of metallic objects placed and moved on its surface."}, {"event": "Machineries", "place": "Strandbühne", "date": "2026-05-09", "time": "2026-05-09, 4:00 pm–4:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/machineries.html", "details": "The duo Machineries is a collaboration between synthesizer sorceresses Mustelide and Chikiss, who conjure their machines to craft soundscapes of electro-baroque and dystopian fantasy fiction.\n\nThe concept took root after discovering the 1984 book \"The Creative Computer\" abandoned on the streets of Berlin, which is dedicated to proto-AI technologies, but in a more romantic and human way. Touching visual canvases and poems composed by the machines of that era inspired the artists to turn to the machines of this time for new stories.\n\nA kind of synthesis of the past & future, a scenario of cosmic chaos, krautrock passages, and web-disco revelations.\n\nInstagram | Bandcamp\n\nPhoto credit: Goestagraph"}, {"event": "Aleksandra Słyż", "place": "Tonarium/Studiobühne", "date": "2026-05-09", "time": "2026-05-09, 4:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/aleksandra-slyz.html", "details": "Aleksandra Słyż is a Polish composer. She holds degrees from Adam Mickiewicz University in Poznań, the Poznań Academy of Music, and the Royal College of Music in Stockholm.\n\nIn her compositions, she explores connections between acoustic and synthetic sounds. This process is often rooted in rational tuning systems, through which she constructs rich, complex drone structures that highlight the power of microtonal, electroacoustic tensions. Interactive sonification systems are another major part of her artistic practice. Between 2017 and 2022, Słyż conducted artistic research involving practical experiments on movement sonification and types of interaction.\n\nHer works have been presented at prestigious contemporary and experimental music festivals and in major venues including Rewire Festival, CTM, Aarhus Festival, Unsound, Warsaw Autumn, ORF musikprotokoll, The Royal Concertgebouw Amsterdam, Fylkingen, Alice Tully Hall, Ancienne Belgique, and Stadtcasino Basel.\n\nAleksandra’s compositions have been performed by exceptional contemporary orchestras and ensembles such as the National Polish Radio Symphony Orchestra, the Basel Sinfonietta, the Sinfonietta Cracovia, the Orchestra of Futurist Noise Intoners, and the Spółdzielnia Muzyczna contemporary ensemble."}, {"event": "Gesprächskonzert - Joranalogue Audio Design", "place": "Kino", "date": "2026-05-09", "time": "2026-05-09, 4:30 pm–4:50 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/gespraechskonzert-joranalogue-4.html", "details": "2026 marks the 10-year anniversary of lead designer Joran van Gremberghe's journey into analogue synthesis—a trajectory entangled with the Superbooth event itself. In this lecture concert, we'll explore the past, present and future of the Joranalogue approach to modular patch-programming."}, {"event": "Hélo Moondi", "place": "Sooper Corner", "date": "2026-05-09", "time": "2026-05-09, 4:40 pm–6:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/helo-moondi.html", "details": "Hélo Moondi is a French, Berlin-based producer and sound artist. Moving between DJ sets, production, and radio, she performs in Berlin at venues such as Grüner Salon (Volksbühne), Kater Blau, ACUD MACHT NEU, and Backsteinboot.\n\nFor Superbooth 2026, she presents a vinyl DJ set rooted in experimental dub and bass music, spinning records to explore slow-building tension and spatial depth, shaping a mysterious and immersive journey between club culture and experimental electronica.\n\nHélo Moondi | Instagram\n\nPhoto credit: Gisèle Chavannes"}, {"event": "Anushka Chkheidze + Robert Lippok", "place": "Seebühne", "date": "2026-05-09", "time": "2026-05-09, 5:00 pm–5:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/anushka-chkheidze-robert-lippok.html", "details": "Anushka Chkheidze is a Georgian composer and sound artist whose work moves between immersive sound installations, choral textures, organ compositions and rhythm-driven electronic music. Robert Lippok, Berlin-based sound artist and long-time explorer of spatial sound and electronic minimalism, has shaped experimental electronic music for decades through composition, performance and visual art.\n\nFirst meeting in 2019 during a workshop programme in Tbilisi, they later collaborated on Glacier Music II before developing a more immediate, real-time approach to making music together. Uncontrollable Thoughts (Morr Music) is their debut joint release — a dialogue between generations that draws on minimal music and late 1990s/early 2000s electronica, merging subtle beats with elegiac organ drones and shifting melodic textures.\n\nAnushka Chkheidze\n\nRobert Lippock\n\nUncontrollable Thoughts\n\nPhoto credit: George Nebieridze"}, {"event": "Gesprächskonzert - Quray", "place": "Kino", "date": "2026-05-09", "time": "2026-05-09, 5:30 pm–5:50 pm", "category": "lecture", "url": "https://www.superbooth.com/en/events/details/gespraechskonzert-quray.html", "details": "Sound is no longer tied to an interface — it moves into space. Music is created without touch: movement becomes a source of sound, notes, and modulation in real time.\n\nQuray is a performative spatial instrument where the space above the device forms a unified playing field, and gestures become sound.\n\nThe performance transitions into a demonstration of how sound emerges from movement and becomes visible."}, {"event": "Stromkult - In Conversation with Aleksandra Słyż", "place": "Stromkult Stage", "date": "2026-05-09", "time": "2026-05-09, 5:30 pm–6:00 pm", "category": "talk", "url": "https://www.superbooth.com/en/events/details/stromkult-in-conversation-with-aleksandra-slyz.html", "details": "For the first time this year, Stromkult , in collaboration with the SuperBooth and SchneidersLaden, is hosting a stage for conversations about electronic music and making electronic music in the cozy Bungalowdorf area of the SuperBooth. Rather than focusing on direct product demos, the idea behind this stage is to provide insight into the philosophies and working processes of the people behind the instruments – as well as the artists using them – through casual live conversation panels."}, {"event": "Megan Leber", "place": "Strandbühne", "date": "2026-05-09", "time": "2026-05-09, 6:00 pm–6:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/megan-leber-2.html", "details": "Megan Leber, labeled as “the Queen of Restraint” by the modular community, is a Rotterdam (NL) based live performer, DJ and producer who is heavily relying on her intuition. Driven by curiosity she uses her modular system with other hardware and pulls the dance floor into her world.\n\nWorking with artists like Speedy J, Rødhåd and Colin Benders for STOOR and releasing tracks on vinyl next to Luke Slater and Ben Sims made her gain ground in the electronic music scene.\n\nHer live sets as well as her hybrid DJ sets range from deeper techno to faster techno and occasionally she’ll weave together an ambient set, making her an exceptionally versatile artist and definitely one to not quickly forget.\n\nInstagram | RA | Soundcloud"}, {"event": "Gudrun Gut", "place": "Sooper Corner", "date": "2026-05-09", "time": "2026-05-09, 6:40 pm–8:00 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/gudrun-gut.html", "details": "Gudrun Gut has been active in the Berlin music scene and part of various bands and projects since 1979 (Mania D., Einstürzende Neubauten, Malaria!, Matador, Davies/Gut, Greie Gut Fraktion, Gut und Irmler, Monika Werkstatt, solo as Gudrun Gut).\n\nShe is a label maker (Monika and Moabit Musik), radio producer (together with Thomas Fehlmann “Ocean Club Radio” for Radio Eins Berlin 1997-2007) and curator (Marke B – Berliner Labelnächte, Um-Festival, Monika Werkstatt).\n\nIn 2019 she received the ‘Listen to Berlin Award’ for the promotion and development of the Berlin music scene. In 2021 she presented the mammoth project M_Dokumente Book and M_Sessions Album – all about Mania D., Malaria!, Matador with a large exhibition, concerts and talks in Berlin with Beate Bartel and Bettina Köster.\n\nIn 2023 she played a leading role in the mini-documentary series GUT for ARD Mediathek (directed by Heiko Lange + Gudrun Gut). Gudrun Gut lives and works in Berlin and the Uckermark.\n\nIn addition to all these activities, Gudrun Gut continues to perform on stage with a vibrant AV performance.\n\nBandcamp | Instagram\n\nPhoto credit: Mara von Kummer"}, {"event": "LYDER", "place": "Seebühne", "date": "2026-05-09", "time": "2026-05-09, 7:00 pm–7:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/lyder.html", "details": "The music project LYDER was born from a fascination with the instrumental playing practice of jazz as well as the love to electronic music production.\n\nUnder their collaborative pseudonym, Lindsey Wang ('Polygonia' - live electronics, vocals, violin), Niklas Bühler ('Delusional Circuits' - live electronics, piano) and Moritz Stahl ('odizouu' - live electronics, saxophone) combine jazz and electronic music by fusing improvisation, live-looping and sound effects into an immersive electroacoustic experience.\n\nTheir broad musical mood spectrum ranges from harmonic and emotional soundscapes to fast, driving rhythms, which create a hypnotic undertow through multi-faceted sound design.\n\nInstagram | Bandcamp | Soundcloud\n\nPhoto credit: George Stirnweiss"}, {"event": "Tunegirl x Colin Benders", "place": "Strandbühne", "date": "2026-05-09", "time": "2026-05-09, 8:00 pm–8:40 pm", "category": "concert", "url": "https://www.superbooth.com/en/events/details/tunegirl-x-colin-benders.html", "details": "Tunegirl and Colin Benders join forces on stage to close out the 10-year anniversary. Both hardly need any intruduction at all....but here you go just in case...."}, {"event": "Aftershow w/ CYRK + TBA", "place": "Waldkater", "date": "2026-05-09", "time": "2026-05-09, 9:00 pm", "category": "evening", "url": "https://www.superbooth.com/en/events/details/aftershow-w-cyrk-tba.html", "details": "The Superbooth 10 year closing party in the beer garden to the right of the FEZ fountain – Wraping up SUPERBOOTH26  with CYRK and TBA . See you there. Cheers!"}];